'use client';
import * as React from 'react';

// Static CSS vars — no ThemeProvider, no Emotion runtime for the theme.
// Generated by: pnpm -F @mui/material build:theme-css
import '@mui/material/default-theme.css';

import Box from '@mui/material/Box';
import Slider from '@mui/material/Slider';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

// 100 sliders rendered with CSS-file styling only.
// No sx prop, no Emotion theme injection.

const COLORS = ['primary', 'secondary', 'error', 'warning', 'info', 'success'] as const;
const SIZES = ['small', 'medium'] as const;

type SliderConfig = {
  color: (typeof COLORS)[number];
  size: (typeof SIZES)[number];
  defaultValue: number;
  disabled: boolean;
  marks: boolean;
};

function buildConfigs(count: number): SliderConfig[] {
  return Array.from({ length: count }, (_, i) => ({
    color: COLORS[i % COLORS.length],
    size: SIZES[i % SIZES.length],
    defaultValue: (i * 13) % 100,
    disabled: i % 10 === 9,
    marks: i % 3 === 0,
  }));
}

const configs = buildConfigs(100);

export default function SliderCssBenchmark() {
  return (
    <Box
      sx={{
        p: { xs: 3, md: 5 },
        bgcolor: 'var(--mui-palette-background-default)',
        color: 'var(--mui-palette-text-primary)',
        minHeight: '100vh',
      }}
    >
      <Typography variant="h5" sx={{ fontWeight: 700, mb: 0.5 }}>
        CSS-only Slider benchmark
      </Typography>
      <Typography
        variant="body2"
        sx={{ color: 'var(--mui-palette-text-secondary)', mb: 4 }}
      >
        100 sliders — default CSS file, no Emotion, no ThemeProvider, no sx prop.
      </Typography>

      <Stack spacing={3}>
        {configs.map((cfg, i) => (

          <Box key={i}>
            <Typography
              variant="caption"
              sx={{ color: 'var(--mui-palette-text-disabled)', display: 'block', mb: 0.5 }}
            >
              #{i + 1} · color={cfg.color} · size={cfg.size}
              {cfg.disabled ? ' · disabled' : ''}
              {cfg.marks ? ' · marks' : ''}
            </Typography>
            <Slider
              defaultValue={cfg.defaultValue}
              color={cfg.color}
              size={cfg.size}
              disabled={cfg.disabled}
              marks={cfg.marks}
            />
          </Box>
        ))}
      </Stack>
    </Box>
  );
}
